### Load point spread data


::: {.cell}

```{.r .cell-code}
library(rlang)
library(cbbplotR)
# schedule <- bigballR::get_team_schedule(team.name="North Carolina",season="2024-25")
# duke_pbp <- bigballR::get_play_by_play(schedule$Game_ID)

pbp_duke <- readr::read_csv("pbp_duke.csv")

no_fts <- pbp_duke |>
  dplyr::mutate(
    scoring = dplyr::case_match(Event_Result,
                                "made" ~ TRUE,
                                "missed" ~ FALSE,
                                NA ~ FALSE),
    pts_value = dplyr::case_when(
      Event_Type == "Turnover" ~ -1,
      Event_Result == "missed" & Shot_Value %in% c(2, 3) ~ 0,
      Event_Result == "made" & Shot_Value == 2 ~ 2,
      Event_Result == "made" & Shot_Value == 3 ~ 3,
      .default = 0
    )) |> 
  dplyr::filter(Event_Type != "Free Throw")

# handle fts separately 
fts <- pbp_duke |> 
  dplyr::filter(Event_Type == "Free Throw") |> 
  dplyr::mutate(
    scoring = dplyr::case_match(Event_Result,
                                "made" ~ TRUE,
                                "missed" ~ FALSE,
                                NA ~ FALSE),
    pts_value = dplyr::case_when(
      Event_Result == "made" & 
        stringr::str_detect(Event_Description, "1of1") ~ 1,
      Event_Result == "made" & 
            stringr::str_detect(Event_Description, "1of2") ~ 1,
        Event_Result == "made" & 
          stringr::str_detect(Event_Description, "2of2") 
          & dplyr::lag( stringr::str_detect(Event_Description, "1of2") &
                      Event_Result == "made") ~ 2,
        Event_Result == "made" & 
          stringr::str_detect(Event_Description, "2of2") 
        & dplyr::lag( stringr::str_detect(Event_Description, "1of2") &
                        Event_Result == "missed") ~ 1,
      Event_Result == "made" & 
        stringr::str_detect(Event_Description, "1of3") ~ 1,
      Event_Result == "made" & 
        stringr::str_detect(Event_Description, "2of3") 
      & dplyr::lag( stringr::str_detect(Event_Description, "1of3") &
                      Event_Result == "made") ~ 2,
      Event_Result == "made" & 
        stringr::str_detect(Event_Description, "2of3") 
      & dplyr::lag( stringr::str_detect(Event_Description, "1of3") &
                      Event_Result == "missed") ~ 1,
      Event_Result == "made" & 
        stringr::str_detect(Event_Description, "3of3") 
      & dplyr::lag( stringr::str_detect(Event_Description, "2of3") &
                      Event_Result == "made") ~ 3,
      Event_Result == "made" & 
        stringr::str_detect(Event_Description, "3of3") 
      & dplyr::lag( stringr::str_detect(Event_Description, "2of3") &
                      Event_Result == "missed") ~ 2,
Event_Result == "missed" & Shot_Value == 1 ~ 0))

game_plot <- no_fts |> 
  dplyr::bind_rows(fts) |> 
  dplyr::arrange(Game_Seconds) |> 
  dplyr::mutate(
    pts_shape = dplyr::case_match(pts_value,
                                  -1 ~ 4,
                                  0 ~ 48,
                                  1 ~ 49,
                                  2 ~ 50,
                                  3 ~ 51),
    scoring_type = dplyr::case_when(
      Event_Type == "Free Throw" & scoring == TRUE ~ "free_throw",
      Shot_Value == 2 & scoring == TRUE ~ "two_pointer",
      Shot_Value == 3 & scoring == TRUE ~ "three_pointer",
      scoring == FALSE ~ "miss",
      TRUE ~ "turnover"
    )
  )
```
:::


### Possession plot


::: {.cell}

```{.r .cell-code}
poss_plot <- game_plot |> 
  ggplot2::ggplot(ggplot2::aes(
    x = Game_Seconds,
    y = Poss_Team,
    color = scoring_type,
    size = pts_value / 2
  )) +
  ggplot2::geom_point(ggplot2::aes(shape = factor(pts_shape)),
                      position = ggplot2::position_dodge(width = 0.5)) +
  ggplot2::scale_color_manual(values = c(
    "free_throw" = "#2E8B57",    # Sea green for free throws
    "two_pointer" = "#006400",   # Dark green for 2-pointers
    "three_pointer" = "#004225",  # Deep forest green for 3-pointers
    "miss" = "#cc0000",          # Red for misses
    "turnover" = "#cc0000"       # Red for turnovers
  )) +
  ggplot2::scale_shape_manual(values = c(4, 45, 49, 50, 51)) +
  ggplot2::scale_x_continuous(breaks = c(0,600, 1200, 1800, 2400), 
                              labels = c("1 minute", "10 minutes", "Halftime", 
                                         "30 Minutes", "40 minutes")) +
  ggplot2::geom_vline(xintercept = 1200,
                      linetype = "dashed",
                      color = "#333333") +
  ggthemes::theme_fivethirtyeight() +
  ggplot2::annotate(
    "rect",
    fill = "#012169",
    alpha = 0.35,
    xmin = 253,
    xmax = 415,
    ymin = -Inf,
    ymax = Inf
  ) +
  ggplot2::annotate(
    "rect",
    fill = "#012169",
    alpha = 0.35,
    xmin = 572,
    xmax = 886,
    ymin = -Inf,
    ymax = Inf
  ) +
  ggplot2::theme(
    legend.position = "none",
    axis.text.y = cbbplotR::element_cbb_teams(size = 0.9),
    panel.grid.major = ggplot2::element_blank(),
    panel.grid.minor = ggplot2::element_blank(),
    panel.background = ggplot2::element_blank(),
    plot.title = ggtext::element_markdown(),
    plot.subtitle = ggtext::element_markdown()
  ) +
  ggplot2::labs(
    x = "Possessions",
    y = "",
    title = "Duke 87, North Carolina 70",
    subtitle = "Scoring possessions shown in different shades of green: <span style='color:#2E8B57'>free throw trips</span>, <span style='color:#006400'>two-pointers</span>, <span style='color:#004225'>three-pointers</span><br>Empty possessions shown in red: <span style='color:#CC0000'>missed shots (-)</span> or <span style='color:#CC0000'>turnovers (x)</span>",
    caption = "data via bigballR + logos via cbbplotR | February 1, 2025 | Table by Chris at Bless your Chart"
  ) + 
  ggplot2::annotate(
    "label",
    x = 2200,
    y = 1.5,
    label = "Points per trip \nDuke: 1.34 PPP  \nUNC: 1.08 PPP  \n65 possessions",
    size = 3,
    color = "#333333",
    fill = "floralwhite",
    fontface = "bold",
    alpha = .3
  ) +
  ggplot2::annotate(
    "label",
    x = 334,
    y = 1.5,
    label = "16-0  \nDuke run",
    size = 3,
    color = "#333333",
    fill = "floralwhite",
    fontface = "bold"
  ) +
  ggplot2::annotate(
    "label",
    x = 729,
    y = 1.5,
    label = "11-0  \nDuke run",
    size = 3,
    color = "#333333",
    fill = "floralwhite",
    fontface = "bold"
  ) 

# save the plot 
ggplot2::ggsave(
  "unc_duke_plot.png",
  poss_plot,
  w = 9.5,
  h = 7,
  dpi = 600,
  type = 'cairo'
)

poss_plot
