### Runs table


::: {.cell}

```{.r .cell-code}
run_header <- glue::glue(
  "<div style='display: flex; justify-content: space-between; align-items: center;'>
      <div>
       <img src='https://a.espncdn.com/combiner/i?img=/i/teamlogos/ncaa/500/153.png'
       style='height: 45px; width: auto; vertical-align: middle;'>
     </div>
     <div style='flex-grow:1; margin-left: 30px; margin-right: 30px'>
       <span style='display: block; font-weight: bold; text-align: center; font-size: 24px;'>North Carolina <br>Opponent Scoring Runs of 10+ points</span>
       <span style='font-size: 14px; font-weight: normal; display: block; text-align: center;'>Shows scoring runs of 10+ points by opponent this season. <br>Carolina is 13-10 overall and 6-5 in the ACC through February 1 games.</span>
     </div>
     <div>
       <img src='https://a.espncdn.com/combiner/i?img=/redesign/assets/img/icons/ESPN-icon-basketball.png'
       style='height: 40px; width: auto; vertical-align: middle;'>
     </div>
   </div>
  <br>"
)

run_tbl <- run_data |>
  cbbplotR::gt_cbb_teams(run_team, run_team) |>
  gt::gt() |>
  gtUtils::gt_theme_gtutils() |>
  gt::fmt_markdown(run_team) |>
  gt::fmt(
    columns = c(run_length),
    fns = function(x) {
      ifelse(x < 0, paste0("+", x), x)
    }
  ) |>
  gtUtils::gt_column_subheaders(
    run_length = list(heading = "Run", subtitle = "# of points"),
    start_score = list(heading = "Start", subtitle = "Score"),
    end_score = list(heading = "End", subtitle = "Score"),
    run_start = list(heading = "Start", subtitle = "Time"),
    run_end = list(heading = "End", subtitle = "Time"),
    time_clean = list(heading = "Total", subtitle = "Time"),
    heading_color = "black",
    subtitle_color = "gray"
  ) |>
  gt::tab_header(title = gt::html(run_header)) |>
  gt::tab_source_note(
    source_note =
      gt::html(
        "<hr>Score shows in perspective of opponent or the team making the run. The runs are also known as kill shots per Evan Miya.<hr>Data via bigballR + theme via {gtUtils} and logos from ESPN.<hr><b>Table by Chris at Bless your chart | data through February 1 games</b>"
      )
  ) |>
  gt::tab_spanner(label = "Time", columns = c(run_start, run_end, time_clean)) |>
  gt::tab_spanner(label = "Score", columns = c(start_score, end_score)) |>
  gt::data_color(
    columns = run_length,
    direction = c("column"),
    method = c("numeric"),
    palette = "Reds"
  ) |> 
  gtUtils::gt_border_bars_bottom(c("#56a0d3", "#89BDE0", "#BBD9ED")) |>
  gt::tab_options(table.width = gt::px(675)) |>
  gtUtils::gt_border_grid(color = "black",
                          weight = 0.5,
                          include_labels = FALSE) |>
  gtExtras::gt_add_divider(columns = run_length,
                           sides = "left",
                           color = "black") |>
  gt::cols_label(run_team = "") |> 
  gt::tab_style(
    locations = gt::cells_source_notes(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      size = gt::px(11.5),
      weight = 250
    )
  ) |>
  gt::tab_style(
    style = list(gt::cell_text(font = gt::google_font("Signika Negative"))),
    locations = gt::cells_body(columns = everything())
  ) |>
  gt::tab_style(
    locations = gt::cells_column_spanners(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      weight = 850,
      size = gt::px(15)
    )
  ) |>
  gt::cols_align(columns = c(run_team), align = "left") |>
  gtExtras::gt_highlight_rows( # this is silly 
    rows = c(2, 4, 6),
    columns = c(run_team),
    fill = "#d0e4f3"
  ) |>
  gtExtras::gt_highlight_rows(
